from __future__ import annotations

import enum
import logging
import ssl
import time
import types
import typing

import h11

from .._backends.base import AsyncNetworkStream
from .._exceptions import (
    ConnectionNotAvailable,
    LocalProtocolError,
    RemoteProtocolError,
    WriteError,
    map_exceptions,
)
from .._models import Origin, Request, Response
from .._synchronization import AsyncLock, AsyncShieldCancellation
from .._trace import Trace
from .interfaces import AsyncConnectionInterface

logger = logging.getLogger("httpcore.http11")


# A subset of `h11.Event` types supported by `_send_event`
H11SendEvent = typing.Union[
    h11.Request,
    h11.Data,
    h11.EndOfMessage,
]


class HTTPConnectionState(enum.IntEnum):
    NEW = 0
    ACTIVE = 1
    IDLE = 2
    CLOSED = 3


class AsyncHTTP11Connection(AsyncConnectionInterface):
    READ_NUM_BYTES = 64 * 1024
    MAX_INCOMPLETE_EVENT_SIZE = 100 * 1024

    def __init__(
        self,
        origin: Origin,
        stream: AsyncNetworkStream,
        keepalive_expiry: float | None = None,
    ) -> None:
        """
        Initialize an HTTP/1.1 connection.

        Parameters:
        - origin: The origin (scheme, host, port) this connection is associated with.
        - stream: The underlying network stream for I/O.
        - keepalive_expiry: Optional number of seconds for keep-alive expiry.
        """
        self._origin = origin
        self._network_stream = stream
        self._keepalive_expiry: float | None = keepalive_expiry
        self._expire_at: float | None = None
        self._state = HTTPConnectionState.NEW
        self._state_lock = AsyncLock()
        self._request_count = 0
        self._h11_state = h11.Connection(
            our_role=h11.CLIENT,
            max_incomplete_event_size=self.MAX_INCOMPLETE_EVENT_SIZE,
        )

    async def handle_async_request(self, request: Request) -> Response:
        if not self.can_handle_request(request.url.origin):
            raise RuntimeError(
                f"Attempted to send request to {request.url.origin} on connection "
                f"to {self._origin}"
            )

        async with self._state_lock:
            if self._state in (HTTPConnectionState.NEW, HTTPConnectionState.IDLE):
                self._request_count += 1
                self._state = HTTPConnectionState.ACTIVE
                self._expire_at = None
            else:
                raise ConnectionNotAvailable()

        try:
            kwargs = {"request": request}
            try:
                async with Trace(
                    "send_request_headers", logger, request, kwargs
                ) as trace:
                    await self._send_request_headers(**kwargs)
                async with Trace("send_request_body", logger, request, kwargs) as trace:
                    await self._send_request_body(**kwargs)
            except WriteError:
                # If we get a write error while we're writing the request,
                # then we supress this error and move on to attempting to
                # read the response. Servers can sometimes close the request
                # pre-emptively and then respond with a well formed HTTP
                # error response.
                pass

            async with Trace(
                "receive_response_headers", logger, request, kwargs
            ) as trace:
                (
                    http_version,
                    status,
                    reason_phrase,
                    headers,
                    trailing_data,
                ) = await self._receive_response_headers(**kwargs)
                trace.return_value = (
                    http_version,
                    status,
                    reason_phrase,
                    headers,
                )

            network_stream = self._network_stream

            # CONNECT or Upgrade request
            if (status == 101) or (
                (request.method == b"CONNECT") and (200 <= status < 300)
            ):
                network_stream = AsyncHTTP11UpgradeStream(network_stream, trailing_data)

            return Response(
                status=status,
                headers=headers,
                content=HTTP11ConnectionByteStream(self, request),
                extensions={"network_stream": network_stream},
                http_version=http_version,
                reason_phrase=reason_phrase,
            )
        finally:
            # If the response body is not consumed synchronously, the connection
            # will be transitioned back to IDLE when the body stream is closed.
            # If an exception occurs here, we need to make sure we don't leave
            # the connection in ACTIVE state.
            async with self._state_lock:
                if self._state == HTTPConnectionState.ACTIVE:
                    # Transition to IDLE; if the connection had expired, mark it.
                    self._state = HTTPConnectionState.IDLE
                    if self._keepalive_expiry is not None:
                        self._expire_at = time.time() + self._keepalive_expiry

    def can_handle_request(self, origin: Origin) -> bool:
        """
        Return True if this connection can be used for the given origin.

        This compares the provided origin with the origin this connection was
        created for.
        """
        return origin == self._origin

    def is_available(self) -> bool:
        """
        Return True if the connection is available for a new request.

        A connection is available if it is in the NEW or IDLE state.
        """
        return self._state in (HTTPConnectionState.NEW, HTTPConnectionState.IDLE)

    def has_expired(self) -> bool:
        """
        Return True if the connection has expired due to keep-alive timeout.

        If no keep-alive expiry was set, this will always return False.
        """
        if self._expire_at is None:
            return False
        return time.time() >= self._expire_at

    def is_idle(self) -> bool:
        """
        Return True if the connection is currently idle.
        """
        return self._state == HTTPConnectionState.IDLE

    def is_closed(self) -> bool:
        """
        Return True if the connection has been closed.
        """
        return self._state == HTTPConnectionState.CLOSED

    def info(self) -> dict:
        """
        Return a dictionary of informational attributes about the connection.

        This is intended for debugging and logging.
        """
        return {
            "origin": self._origin,
            "state": self._state.name,
            "request_count": self._request_count,
            "expire_at": self._expire_at,
        }

    def __repr__(self) -> str:
        """
        Return a concise representation of the connection for debugging.
        """
        return (
            f"<AsyncHTTP11Connection state={self._state.name} origin={self._origin!r} "
            f"requests={self._request_count}>"
        )

    async def _send_request_headers(self, request: Request) -> None:
        """
        Send the request headers over the connection.

        This builds an h11.Request event and sends it to the remote server.
        """
        method = request.method
        target = request.url.raw_path
        # Construct headers: convert to list of tuples if necessary.
        headers = []
        if hasattr(request, "headers"):
            # Expecting request.headers to be an iterable of (name, value).
            try:
                headers = list(request.headers)
            except Exception:
                headers = []
        event = h11.Request(method=method, target=target, headers=headers)
        self._send_event(event)
        await self._send_outgoing()

    async def _send_request_body(self, request: Request) -> None:
        """
        Send the request body, streaming it if necessary.

        If the request has a body stream, iterate over it and send Data events.
        Finally send an EndOfMessage event.
        """
        # Many Request implementations expose an async stream via request.stream.
        stream = getattr(request, "stream", None)
        if stream is None:
            # No body to send.
            self._send_event(h11.EndOfMessage())
            await self._send_outgoing()
            return

        # Read until exhausted. Different stream implementations may provide
        # different APIs (e.g., aread or read); try common ones.
        read_coroutine = getattr(stream, "aread", None) or getattr(stream, "read", None)
        if read_coroutine is None:
            # Not a streaming body we understand; treat as empty.
            self._send_event(h11.EndOfMessage())
            await self._send_outgoing()
            return

        try:
            while True:
                chunk = await read_coroutine(AsyncHTTP11Connection.READ_NUM_BYTES)  # type: ignore[arg-type]
                if not chunk:
                    break
                self._send_event(h11.Data(data=chunk))
                await self._send_outgoing()
        finally:
            # Ensure the stream is closed if it supports aclose.
            aclose = getattr(stream, "aclose", None)
            if aclose is not None:
                try:
                    await aclose()
                except Exception:
                    # Ignore errors while closing request body stream.
                    pass

        self._send_event(h11.EndOfMessage())
        await self._send_outgoing()

    async def _receive_response_headers(self, request: Request) -> tuple:
        """
        Receive and parse the response headers from the remote server.

        Returns a tuple of (http_version, status, reason_phrase, headers, trailing_data).
        """
        # Loop reading from network until we receive a Response event.
        while True:
            try:
                event = self._h11_state.next_event()
            except h11.RemoteProtocolError as exc:
                raise RemoteProtocolError(str(exc)) from exc

            if isinstance(event, h11.Response):
                status = event.status_code
                reason_bytes = event.reason
                try:
                    reason_phrase = reason_bytes.decode("latin-1") if isinstance(reason_bytes, (bytes, bytearray)) else str(reason_bytes)
                except Exception:
                    reason_phrase = str(reason_bytes)
                http_version = f"HTTP/1.1"
                headers = [(name.decode("latin-1") if isinstance(name, (bytes, bytearray)) else name,
                            value.decode("latin-1") if isinstance(value, (bytes, bytearray)) else value)
                           for name, value in event.headers]
                trailing = b""
                return http_version, status, reason_phrase, headers, trailing

            elif isinstance(event, h11.NEED_DATA):
                # Read from the network and feed into h11.
                data = await self._read_from_network()
                if not data:
                    raise RemoteProtocolError("Server disconnected before sending a response.")
                try:
                    self._h11_state.receive_data(data)
                except h11.RemoteProtocolError as exc:
                    raise RemoteProtocolError(str(exc)) from exc
                continue

            else:
                # Unexpected event, try to read more data or raise.
                if isinstance(event, h11.ConnectionClosed):
                    raise RemoteProtocolError("Connection closed while waiting for response.")
                # For other events, attempt to read more.
                data = await self._read_from_network()
                if not data:
                    raise RemoteProtocolError("Server disconnected while waiting for response.")
                try:
                    self._h11_state.receive_data(data)
                except h11.RemoteProtocolError as exc:
                    raise RemoteProtocolError(str(exc)) from exc

    async def _read_from_network(self) -> bytes:
        """
        Read raw bytes from the underlying network stream.
        """
        try:
            data = await self._network_stream.receive(self.READ_NUM_BYTES)
            return data or b""
        except Exception as exc:
            # Map network-level exceptions to library-level ones where appropriate.
            raise

    def _send_event(self, event: H11SendEvent) -> None:
        """
        Send an h11 event into the internal state machine, producing bytes
        that can be flushed to the network.
        """
        try:
            data = self._h11_state.send(event)
        except h11.LocalProtocolError as exc:
            raise LocalProtocolError(str(exc)) from exc
        # Buffer the outgoing bytes by storing them on the h11 state. They will be
        # retrieved and written out by _send_outgoing.
        # h11.Connection.send already buffers and returns bytes, so no buffering needed here.
        # We rely on _send_outgoing to actually write the bytes.

    async def _send_outgoing(self) -> None:
        """
        Flush any pending outgoing data from the h11 state to the network.
        """
        while True:
            try:
                data = self._h11_state.data_to_send()
            except h11.LocalProtocolError as exc:
                raise LocalProtocolError(str(exc)) from exc
            if not data:
                break
            try:
                await self._network_stream.send(data)
            except Exception as exc:
                raise WriteError(str(exc)) from exc

    def _get_outgoing_data(self) -> bytes:
        """
        Return any outgoing buffered data from h11 without sending it.
        """
        try:
            return self._h11_state.data_to_send()
        except h11.LocalProtocolError as exc:
            raise LocalProtocolError(str(exc)) from exc

    async def close(self) -> None:
        """
        Close the underlying network stream and mark the connection as closed.
        """
        async with self._state_lock:
            if self._state == HTTPConnectionState.CLOSED:
                return
            self._state = HTTPConnectionState.CLOSED
        try:
            await self._network_stream.aclose()
        except Exception:
            pass


class HTTP11ConnectionByteStream:
    def __init__(self, connection: AsyncHTTP11Connection, request: Request) -> None:
        """
        Async byte stream for reading the response body from an HTTP/1.1 connection.

        Parameters:
        - connection: The AsyncHTTP11Connection instance the stream will read from.
        - request: The original Request object associated with this response.
        """
        self._connection = connection
        self._request = request
        self._closed = False

    async def aread(self, n: int = -1) -> bytes:
        """
        Read up to n bytes from the response body. If n is -1, read as much as available.

        This implementation delegates to the underlying h11 parser and network stream.
        """
        if self._closed:
            return b""
        # Attempt to get next Data event from h11.
        while True:
            try:
                event = self._connection._h11_state.next_event()
            except h11.RemoteProtocolError as exc:
                raise RemoteProtocolError(str(exc)) from exc

            if isinstance(event, h11.Data):
                data = bytes(event.data)
                # Inform h11 we've consumed the data.
                return data
            elif isinstance(event, h11.EndOfMessage):
                # Response body complete.
                await self.aclose()
                return b""
            elif isinstance(event, h11.NEED_DATA):
                # Need to read raw bytes into h11 parser.
                data = await self._connection._read_from_network()
                if not data:
                    # Connection closed unexpectedly.
                    await self.aclose()
                    return b""
                try:
                    self._connection._h11_state.receive_data(data)
                except h11.RemoteProtocolError as exc:
                    raise RemoteProtocolError(str(exc)) from exc
                continue
            else:
                # Unexpected event: try reading from network.
                data = await self._connection._read_from_network()
                if not data:
                    await self.aclose()
                    return b""
                try:
                    self._connection._h11_state.receive_data(data)
                except h11.RemoteProtocolError as exc:
                    raise RemoteProtocolError(str(exc)) from exc

    async def aclose(self) -> None:
        """
        Close the byte stream, transitioning the connection back to IDLE if appropriate.
        """
        if self._closed:
            return
        self._closed = True
        async with self._connection._state_lock:
            if self._connection._state == HTTPConnectionState.ACTIVE:
                self._connection._state = HTTPConnectionState.IDLE
                if self._connection._keepalive_expiry is not None:
                    self._connection._expire_at = time.time() + self._connection._keepalive_expiry


class AsyncHTTP11UpgradeStream(AsyncNetworkStream):
    def __init__(self, stream: AsyncNetworkStream, initial_bytes: bytes) -> None:
        """
        Wrap the underlying network stream for a protocol upgrade response.

        Parameters:
        - stream: The original network stream which will be used for raw I/O.
        - initial_bytes: Any bytes already read from the stream that should be
                         returned on the first read.
        """
        self._stream = stream
        self._initial = initial_bytes or b""
        self._initial_consumed = False

    async def receive(self, n: int = -1) -> bytes:
        """
        Receive up to n bytes from the upgraded stream.

        Any initial bytes captured during the upgrade handshake will be returned
        before delegating to the underlying stream.
        """
        if not self._initial_consumed:
            self._initial_consumed = True
            if self._initial:
                if n == -1 or n >= len(self._initial):
                    data = self._initial
                    self._initial = b""
                    return data
                else:
                    data = self._initial[:n]
                    self._initial = self._initial[n:]
                    return data
        return await self._stream.receive(n)

    async def send(self, data: bytes) -> None:
        """
        Send data over the upgraded stream.
        """
        await self._stream.send(data)

    async def aclose(self) -> None:
        """
        Close the upgraded stream.
        """
        await self._stream.aclose()

    def get_extra_info(self, name: str, default: typing.Any = None) -> typing.Any:
        """
        Return optional transport information for the upgraded stream.

        Delegates to the underlying stream's get_extra_info if available.
        """
        get_info = getattr(self._stream, "get_extra_info", None)
        if get_info is None:
            return default
        return get_info(name, default)